"""Global cost, token, and activity aggregation queries for the dashboard.

Two data sources feed the dashboard summary:

1. ``claude_log_statuslines`` — cost and token counters (monotonic per
   instance window, delta-based aggregation).
2. ``claude_log_hooks`` — session count (distinct session_ids) and
   message count (Stop events on the main agent × 2, reflecting one
   user prompt + one assistant response per exchange).

The two result sets are merged by day (or day+cwd) in Python. Days that
appear in one source but not the other get zeros for the missing fields.

cost_usd and the token counters (total_input_tokens, total_output_tokens)
are monotonic per instance window — a contiguous span of activity on a
(pid, source_system, cwd) tuple bounded by claude_log_pid_deaths rows.
Across windows the counters reset, so we group by
``(pid, source_system, cwd, prior_death)`` and compute deltas separately
within each group.
"""

import aiosqlite

_COST_CTE = """
WITH instance_rows AS (
    SELECT
        s.cwd AS cwd,
        s.cost_usd AS cost_usd,
        s.total_input_tokens AS total_input_tokens,
        s.total_output_tokens AS total_output_tokens,
        s.received_at AS received_at,
        s.pid AS pid,
        s.source_system AS source_system,
        COALESCE(
            (SELECT MAX(observed_at) FROM claude_log_pid_deaths d
             WHERE d.pid = s.pid
                   AND d.source_system = s.source_system
                   AND d.cwd = s.cwd
                   AND d.observed_at < s.received_at),
            -1.0
        ) AS prior_death
    FROM claude_log_statuslines s
    WHERE s.cost_usd IS NOT NULL
),
day_max AS (
    SELECT
        date(received_at, 'unixepoch', 'localtime') AS day,
        cwd,
        pid,
        source_system,
        prior_death,
        MAX(cost_usd) AS day_max_cost,
        COALESCE(MAX(total_input_tokens), 0) AS day_max_input,
        COALESCE(MAX(total_output_tokens), 0) AS day_max_output
    FROM instance_rows
    GROUP BY pid, source_system, cwd, prior_death, day
),
deltas AS (
    SELECT
        day,
        cwd,
        day_max_cost - LAG(day_max_cost, 1, 0.0)
            OVER w AS cost_delta,
        day_max_input - LAG(day_max_input, 1, 0)
            OVER w AS input_delta,
        day_max_output - LAG(day_max_output, 1, 0)
            OVER w AS output_delta
    FROM day_max
    WINDOW w AS (
        PARTITION BY pid, source_system, cwd, prior_death ORDER BY day
    )
)
"""


def _empty_row(day: str, *, cwd: str | None = None) -> dict:
    row: dict = {
        "day": day,
        "session_count": 0,
        "message_count": 0,
        "total_tokens": 0,
        "total_cost_usd": 0.0,
    }
    if cwd is not None:
        row["cwd"] = cwd
    return row


async def costs_by_day(db: aiosqlite.Connection) -> list[dict]:
    """Summary metrics per day (server local time).

    Returns rows ordered by ``day`` descending. Each row has ``day``,
    ``session_count``, ``message_count``, ``total_tokens``,
    ``total_cost_usd``.
    """
    cursor = await db.execute(_COST_CTE + """
        SELECT day,
               ROUND(SUM(cost_delta), 6) AS total_cost_usd,
               SUM(input_delta) + SUM(output_delta) AS total_tokens
        FROM deltas
        GROUP BY day
        """)
    cost_rows = await cursor.fetchall()

    cursor = await db.execute("""
        SELECT
            date(received_at, 'unixepoch', 'localtime') AS day,
            COUNT(DISTINCT session_id) AS session_count,
            SUM(CASE WHEN event_name = 'Stop' AND agent_id IS NULL
                THEN 1 ELSE 0 END) * 2 AS message_count
        FROM claude_log_hooks
        GROUP BY day
        """)
    activity_rows = await cursor.fetchall()

    merged: dict[str, dict] = {}
    for r in cost_rows:
        day = r["day"]
        merged[day] = _empty_row(day)
        merged[day]["total_cost_usd"] = float(r["total_cost_usd"])
        merged[day]["total_tokens"] = int(r["total_tokens"] or 0)
    for r in activity_rows:
        day = r["day"]
        if day not in merged:
            merged[day] = _empty_row(day)
        merged[day]["session_count"] = int(r["session_count"])
        merged[day]["message_count"] = int(r["message_count"])

    return sorted(merged.values(), key=lambda x: x["day"], reverse=True)


async def costs_by_day_cwd(db: aiosqlite.Connection) -> list[dict]:
    """Summary metrics per (day, cwd).

    Returns rows ordered by ``day`` descending then ``cwd`` ascending.
    Each row has ``day``, ``cwd``, plus the same fields as
    ``costs_by_day``.
    """
    cursor = await db.execute(_COST_CTE + """
        SELECT day, cwd,
               ROUND(SUM(cost_delta), 6) AS total_cost_usd,
               SUM(input_delta) + SUM(output_delta) AS total_tokens
        FROM deltas
        GROUP BY day, cwd
        """)
    cost_rows = await cursor.fetchall()

    cursor = await db.execute("""
        SELECT
            date(received_at, 'unixepoch', 'localtime') AS day,
            cwd,
            COUNT(DISTINCT session_id) AS session_count,
            SUM(CASE WHEN event_name = 'Stop' AND agent_id IS NULL
                THEN 1 ELSE 0 END) * 2 AS message_count
        FROM claude_log_hooks
        GROUP BY day, cwd
        """)
    activity_rows = await cursor.fetchall()

    merged: dict[tuple[str, str], dict] = {}
    for r in cost_rows:
        key = (r["day"], r["cwd"])
        merged[key] = _empty_row(r["day"], cwd=r["cwd"])
        merged[key]["total_cost_usd"] = float(r["total_cost_usd"])
        merged[key]["total_tokens"] = int(r["total_tokens"] or 0)
    for r in activity_rows:
        key = (r["day"], r["cwd"])
        if key not in merged:
            merged[key] = _empty_row(r["day"], cwd=r["cwd"])
        merged[key]["session_count"] = int(r["session_count"])
        merged[key]["message_count"] = int(r["message_count"])

    result = sorted(merged.values(), key=lambda x: x["cwd"])
    result.sort(key=lambda x: x["day"], reverse=True)
    return result
